from __future__ import annotations

from dataclasses import dataclass
from datetime import date
import ast
import json
import math
from typing import Iterable

import numpy as np
import pandas as pd
import difflib

from ..config.settings import Settings
from ..data.akshare_client import AkShareClient
from ..data.cache import load_csv, save_csv
from ..data.spot_cache import get_a_spot
from ..data.xueqiu_client import XueqiuClient
from ..utils.dates import shift_days, yyyymmdd
from ..utils.jsonio import write_json
from ..utils.paths import Paths


@dataclass(frozen=True)
class IndustrySelection:
    industries: list[str]
    table: pd.DataFrame
    source: str


def _safe_name(s: str) -> str:
    return "".join(ch if ch.isalnum() or ch in {"_", "-", "."} else "_" for ch in s)


def _parse_impacts(x: object) -> list[dict[str, object]]:
    if x is None or (isinstance(x, float) and np.isnan(x)):
        return []
    if isinstance(x, list):
        return [i for i in x if isinstance(i, dict)]
    s = str(x).strip()
    if not s:
        return []
    try:
        v = json.loads(s)
        if isinstance(v, list):
            return [i for i in v if isinstance(i, dict)]
    except Exception:
        try:
            v = ast.literal_eval(s)
            if isinstance(v, list):
                return [i for i in v if isinstance(i, dict)]
        except Exception:
            return []
    return []


def _map_sector_to_ths(sector: str, industries: list[str]) -> list[str]:
    s = str(sector).strip()
    if not s:
        return []

    rules: list[tuple[list[str], list[str]]] = [
        (["油", "气", "原油", "石油"], ["油气", "石油", "油服", "炼化"]),
        (["煤", "焦"], ["煤炭", "焦"]),
        (["航运", "港口", "红海", "海运", "集运"], ["港口", "航运", "物流"]),
        (["航空", "机场"], ["航空", "机场"]),
        (["化工", "乙烯", "塑料", "化学"], ["化学", "化工", "塑料"]),
        (["黄金", "贵金属"], ["贵金属", "黄金"]),
        (["军工", "国防", "导弹", "武器"], ["国防", "军工"]),
        (["银行"], ["银行"]),
        (["证券", "券商"], ["证券"]),
        (["保险"], ["保险"]),
        (["旅游", "酒店"], ["旅游", "酒店"]),
        (["光伏"], ["光伏"]),
        (["新能源", "电池", "锂"], ["新能源", "电池", "锂"]),
    ]

    cand: list[str] = []
    for keys, pats in rules:
        if any(k in s for k in keys):
            for ind in industries:
                if any(p in ind for p in pats):
                    cand.append(ind)
            break

    if cand:
        uniq: list[str] = []
        seen: set[str] = set()
        for x in cand:
            if x not in seen:
                uniq.append(x)
                seen.add(x)
        return uniq[:3]

    matches = difflib.get_close_matches(s, industries, n=3, cutoff=0.60)
    return [m for m in matches if m]


def _industry_news_boost(out_dir: "Paths", industries: list[str]) -> pd.DataFrame:
    news_path = out_dir / "news_items.csv"
    if not news_path.exists():
        return pd.DataFrame({"industry": industries, "news_delta": 0.0, "news_boost": 0.0})
    try:
        df = pd.read_csv(news_path)
    except Exception:
        return pd.DataFrame({"industry": industries, "news_delta": 0.0, "news_boost": 0.0})

    if "impacts" not in df.columns:
        return pd.DataFrame({"industry": industries, "news_delta": 0.0, "news_boost": 0.0})

    delta: dict[str, float] = {ind: 0.0 for ind in industries}
    for r in df.itertuples(index=False):
        try:
            strength = float(getattr(r, "strength", 1.0))
            sentiment = float(getattr(r, "sentiment", 0.0))
            impacts = _parse_impacts(getattr(r, "impacts", ""))
        except Exception:
            continue
        if not impacts:
            continue
        mag = max(0.2, abs(sentiment))
        for it in impacts[:3]:
            sector = str(it.get("sector") or it.get("industry") or "").strip()
            direction = it.get("direction", 0)
            try:
                direction_i = int(direction)
            except Exception:
                direction_i = 0
            if direction_i not in (-1, 1):
                continue
            mapped = _map_sector_to_ths(sector, industries)
            if not mapped:
                continue
            d = float(direction_i) * float(strength) * mag
            for ind in mapped:
                delta[ind] = float(delta.get(ind, 0.0)) + d

    rows = []
    for ind in industries:
        s = float(delta.get(ind, 0.0))
        boost = 0.03 * math.tanh(s / 6.0)
        rows.append({"industry": ind, "news_delta": s, "news_boost": boost})
    return pd.DataFrame(rows)


def _to_close_series(df: pd.DataFrame) -> pd.Series:
    cols = {c: str(c).lower() for c in df.columns}
    close_col = next((c for c, lc in cols.items() if lc in {"close", "收盘"} or "收盘" in lc), None)
    if close_col is None:
        close_col = next((c for c, lc in cols.items() if "close" in lc), None)
    if close_col is None:
        raise RuntimeError("industry hist missing close column")
    return pd.to_numeric(df[close_col], errors="coerce").dropna()


def _ret_n(close: pd.Series, n: int) -> float:
    if len(close) < n + 1:
        return float("nan")
    a = float(close.iloc[-n - 1])
    b = float(close.iloc[-1])
    if a <= 0:
        return float("nan")
    return (b / a) - 1.0


def _vol_n(close: pd.Series, n: int) -> float:
    if len(close) < n + 1:
        return float("nan")
    r = close.pct_change().dropna().tail(n)
    if r.empty:
        return float("nan")
    return float(np.std(r, ddof=0))


def run(run_date: date, settings: Settings, paths: Paths, news_counts: dict[str, int] | None = None) -> IndustrySelection:
    ymd = yyyymmdd(run_date)
    out_dir = paths.preopen_dir(ymd)
    cache_dir = paths.cache_dir() / "industry_hist"
    cache_dir.mkdir(parents=True, exist_ok=True)

    start = yyyymmdd(shift_days(run_date, -260))
    end = ymd

    xq = XueqiuClient(token_cache_path=paths.cache_dir() / "xueqiu" / "xueqiu_token.json")
    xq_cache = paths.cache_dir() / "xueqiu_basic"

    try:
        spot = get_a_spot(paths.cache_dir())
        code_col = next((c for c in spot.columns if "代码" in str(c) or str(c).lower() in {"code", "symbol"}), spot.columns[0])
        name_col = next((c for c in spot.columns if "名称" in str(c) or str(c).lower() == "name"), spot.columns[1] if len(spot.columns) > 1 else spot.columns[0])
        amt_col = next((c for c in spot.columns if "成交额" in str(c) or "amount" in str(c).lower()), spot.columns[-2] if len(spot.columns) > 1 else spot.columns[-1])

        spot = spot.copy()
        spot["code"] = spot[code_col].astype(str).str.strip().str.zfill(6)
        spot["name"] = spot[name_col].astype(str)
        spot["turnover"] = pd.to_numeric(spot[amt_col], errors="coerce").fillna(0.0)
        spot = spot[spot["code"].str.startswith(("60", "00"))]
        spot = spot[~spot["code"].str.startswith(("300", "688", "689", "8", "4"))]
        if settings.exclude_st:
            spot = spot[~spot["name"].str.contains("ST", regex=False)]
        spot = spot.sort_values("turnover", ascending=False).head(800)

        codes = spot["code"].astype(str).tolist()
        basics = xq.get_stock_basic_batch(codes, cache_dir=xq_cache)
        bdf = pd.DataFrame([b.__dict__ for b in basics])
        bdf = bdf[bdf["industry_l1"].astype(str).str.len() > 0]
        if bdf.empty:
            raise RuntimeError("xueqiu returned empty industry mapping")

        ohlcv_cache = paths.cache_dir() / "ohlcv"
        ohlcv_cache.mkdir(parents=True, exist_ok=True)

        rows: list[dict[str, object]] = []
        for r in bdf.itertuples(index=False):
            code = str(r.code)
            cache_path = ohlcv_cache / f"{code}.csv"
            hist = load_csv(cache_path)
            if hist is None or hist.empty:
                try:
                    hist = AkShareClient().stock_hist(symbol=code, start_ymd=start, end_ymd=end)
                    if isinstance(hist, pd.DataFrame) and not hist.empty:
                        save_csv(hist, cache_path)
                except Exception:
                    continue
            if hist is None or hist.empty:
                continue

            cols = {c: str(c).lower() for c in hist.columns}
            ccol = next((c for c, n in cols.items() if n == "close" or "收盘" in n), None)
            if ccol is None:
                continue
            close = pd.to_numeric(hist[ccol], errors="coerce").dropna()
            if len(close) < 25:
                continue
            ret20 = float(close.iloc[-1] / close.iloc[-21] - 1.0)
            ret5 = float(close.iloc[-1] / close.iloc[-6] - 1.0)
            vol20 = float(close.pct_change().dropna().tail(20).std(ddof=0))
            rows.append({"industry": str(r.industry_l1), "ret20": ret20, "ret5": ret5, "vol20": vol20, "stock": code})

        if rows:
            tmp = pd.DataFrame(rows)
            table = (
                tmp.groupby("industry", as_index=False)
                .agg(ret20=("ret20", "mean"), ret5=("ret5", "mean"), vol20=("vol20", "mean"), n=("stock", "count"))
                .assign(score=lambda d: 0.60 * d["ret20"] + 0.30 * d["ret5"] - 0.10 * d["vol20"])
                .sort_values(["score", "n"], ascending=[False, False])
                .reset_index(drop=True)
            )

            selected = table.head(int(settings.top_k_industries))["industry"].astype(str).tolist()
            save_csv(table, out_dir / "industries_rank.csv")
            write_json({"date": ymd, "top_k": int(settings.top_k_industries), "industries": selected, "source": "xueqiu"}, out_dir / "selected_industries.json")
            return IndustrySelection(industries=selected, table=table, source="xueqiu")
    except Exception:
        pass

    names_df = AkShareClient().industry_names()
    if not isinstance(names_df, pd.DataFrame):
        raise RuntimeError("industry_names returned non-DataFrame")

    name_col = next((c for c in names_df.columns if "名称" in str(c) or "name" in str(c).lower()), None)
    if name_col is None:
        name_col = names_df.columns[0]
    industries = [str(x).strip() for x in names_df[name_col].dropna().tolist()]
    news_boost_df = _industry_news_boost(out_dir, industries)
    boost_map = {str(r.industry): float(r.news_boost) for r in news_boost_df.itertuples(index=False)}

    rows: list[dict[str, object]] = []
    for ind in industries:
        try:
            cache_path = cache_dir / f"{_safe_name(ind)}.csv"
            hist = load_csv(cache_path)
            if hist is None or hist.empty:
                hist = AkShareClient().industry_hist(industry_name=ind, start_ymd=start, end_ymd=end)
                if isinstance(hist, pd.DataFrame) and not hist.empty:
                    save_csv(hist, cache_path)
            elif "日期" in hist.columns:
                last = str(hist["日期"].iloc[-1]).replace("-", "")
                if last < end:
                    hist = AkShareClient().industry_hist(industry_name=ind, start_ymd=start, end_ymd=end)
                    if isinstance(hist, pd.DataFrame) and not hist.empty:
                        save_csv(hist, cache_path)

            close = _to_close_series(hist)
            ret20 = _ret_n(close, 20)
            ret5 = _ret_n(close, 5)
            vol20 = _vol_n(close, 20)
            score_mom = 0.60 * ret20 + 0.30 * ret5 - 0.10 * vol20
            score = float(score_mom) + float(boost_map.get(ind, 0.0))
            rows.append(
                {
                    "industry": ind,
                    "ret20": ret20,
                    "ret5": ret5,
                    "vol20": vol20,
                    "score_mom": score_mom,
                    "news_boost": float(boost_map.get(ind, 0.0)),
                    "score": score,
                }
            )
        except Exception:
            continue

    table = pd.DataFrame(rows)
    table = table.replace([np.inf, -np.inf], np.nan).dropna(subset=["score"]).sort_values("score", ascending=False)
    table = table.reset_index(drop=True)

    selected = table.head(int(settings.top_k_industries))["industry"].astype(str).tolist()

    save_csv(table, out_dir / "industries_rank.csv")
    save_csv(news_boost_df.sort_values("news_boost", ascending=False), out_dir / "industry_news_boost.csv")
    write_json({"date": ymd, "top_k": int(settings.top_k_industries), "industries": selected, "source": "ths"}, out_dir / "selected_industries.json")

    return IndustrySelection(industries=selected, table=table, source="ths")

from __future__ import annotations

from dataclasses import dataclass
from datetime import date
from typing import Any

from concurrent.futures import ThreadPoolExecutor, as_completed
import pandas as pd

from ..config.settings import Settings
from ..config.llm_runtime import load_llm_runtime
from ..data.akshare_client import AkShareClient
from ..data.cache import save_csv
from ..utils.dates import yyyymmdd
from ..utils.jsonio import write_json
from ..utils.paths import Paths
from ..utils.llm_client import LLMClient


@dataclass(frozen=True)
class NewsSignals:
    cash_score: float
    counts: dict[str, int]
    headlines: list[str]


def _norm_text(x: Any) -> str:
    if x is None:
        return ""
    return str(x).strip()


def _classify(text: str) -> tuple[set[str], int]:
    t = text
    cats: set[str] = set()

    monetary = ["央行", "降准", "降息", "MLF", "LPR", "逆回购", "流动性", "货币政策"]
    fiscal = ["财政", "专项债", "产业", "补贴", "规划", "投资", "项目", "招标", "税", "国企改革"]
    regulatory = ["监管", "证监会", "交易所", "严查", "处罚", "减持", "IPO", "再融资", "退市", "量化", "融券", "两融"]
    international = ["美联储", "FOMC", "美元", "汇率", "中美", "关税", "制裁", "油价", "OPEC", "地缘", "战争", "俄乌", "以色列", "伊朗"]

    if any(k in t for k in monetary):
        cats.add("monetary")
    if any(k in t for k in fiscal):
        cats.add("fiscal_industry")
    if any(k in t for k in regulatory):
        cats.add("regulatory")
    if any(k in t for k in international):
        cats.add("international")

    risk_words = ["加息", "收紧", "制裁", "关税", "冲突", "爆雷", "违约", "暴跌", "监管严查", "退市", "处罚"]
    ease_words = ["降准", "降息", "宽松", "呵护", "支持", "稳增长", "刺激", "增量", "专项债", "减税"]

    strength = 1
    strength += int(sum(1 for k in risk_words if k in t) >= 2 or sum(1 for k in ease_words if k in t) >= 2)
    strength += int("重磅" in t or "突发" in t or "紧急" in t)

    return cats, min(strength, 3)


def _telegraph_to_items(df: pd.DataFrame, source: str) -> pd.DataFrame:
    lower_cols = {c: str(c).lower() for c in df.columns}
    title_col = next((c for c, lc in lower_cols.items() if "title" in lc or "标题" in lc), None)
    content_col = next((c for c, lc in lower_cols.items() if "content" in lc or "内容" in lc or "摘要" in lc), None)
    time_col = next((c for c, lc in lower_cols.items() if "time" in lc or "时间" in lc or "发布时间" in lc), None)

    if title_col is None:
        title_col = df.columns[0]
    if content_col is None:
        content_col = title_col

    return pd.DataFrame(
        {
            "source": source,
            "timestamp": df[time_col].map(_norm_text) if time_col is not None else "",
            "title": df[title_col].map(_norm_text),
            "content": df[content_col].map(_norm_text),
        }
    )


def run(run_date: date, settings: Settings, paths: Paths) -> NewsSignals:
    ymd = yyyymmdd(run_date)
    out_dir = paths.preopen_dir(ymd)

    frames: list[pd.DataFrame] = []
    for source, fn in [
        ("cls", AkShareClient().cls_telegraph),
        ("ths", AkShareClient().ths_telegraph),
        ("em", AkShareClient().em_telegraph),
    ]:
        try:
            df = fn()
            if isinstance(df, pd.DataFrame) and not df.empty:
                frames.append(_telegraph_to_items(df, source=source))
        except Exception:
            continue

    if not frames:
        raise RuntimeError("no telegraph sources available")

    out_raw = pd.concat(frames, ignore_index=True)
    out_raw = out_raw.dropna(subset=["title"]).drop_duplicates(subset=["title"]).reset_index(drop=True)
    out_raw["text"] = (out_raw["title"].astype(str) + " " + out_raw["content"].astype(str)).str.strip()

    llm_rt = load_llm_runtime()
    llm = LLMClient(
        api_key=llm_rt.api_key,
        base_url=llm_rt.base_url,
        model=llm_rt.model,
        temperature=llm_rt.temperature,
    )
    batch_size = int(llm_rt.batch_size)
    max_workers = int(llm_rt.max_workers)

    records = out_raw[["title", "content"]].to_dict("records")
    batches = [records[i : i + batch_size] for i in range(0, len(records), batch_size)]

    all_results_map: dict[int, list[dict[str, Any]]] = {}
    with ThreadPoolExecutor(max_workers=max_workers) as executor:
        future_to_idx = {executor.submit(llm.process_news_batch, batch): i for i, batch in enumerate(batches)}
        for future in as_completed(future_to_idx):
            idx = future_to_idx[future]
            batch_len = len(batches[idx])
            try:
                results = future.result()
                while len(results) < batch_len:
                    results.append({"is_noise": True, "sentiment": 0.0, "category": "other", "strength": 1, "impacts": []})
                all_results_map[idx] = results[:batch_len]
            except Exception:
                all_results_map[idx] = [{"is_noise": True, "sentiment": 0.0, "category": "other", "strength": 1, "impacts": []} for _ in range(batch_len)]

    all_results: list[dict[str, Any]] = []
    for i in range(len(batches)):
        all_results.extend(all_results_map.get(i, [{"is_noise": True, "sentiment": 0.0, "category": "other", "strength": 1, "impacts": []} for _ in batches[i]]))

    res_df = pd.DataFrame(all_results)
    for col, default in [("is_noise", True), ("sentiment", 0.0), ("category", "other"), ("strength", 1), ("impacts", [])]:
        if col not in res_df.columns:
            res_df[col] = default

    out = pd.concat([out_raw, res_df], axis=1)
    out = out[out["is_noise"] != True].copy()
    if out.empty:
        out = pd.concat([out_raw, res_df], axis=1).head(30)

    counts = {"monetary": 0, "fiscal_industry": 0, "regulatory": 0, "international": 0}
    for cat in out['category'].dropna():
        if cat in counts:
            counts[cat] += 1

    risk_impact = float(out[out['sentiment'] < -0.3]['strength'].sum())
    ease_impact = float(out[out['sentiment'] > 0.3]['strength'].sum())

    cash_score = float(settings.cash_score_base)
    if risk_impact > 0:
        cash_score += settings.cash_score_risk_add * min(1.0, risk_impact / 10.0)
    if ease_impact > 0:
        cash_score -= settings.cash_score_ease_sub * min(1.0, ease_impact / 10.0)
    cash_score = float(min(0.90, max(0.40, cash_score)))

    top = out.sort_values(["strength", "sentiment"], ascending=[False, True]).head(25)
    headlines = (top["source"].astype(str) + " | " + top["title"].astype(str)).tolist()

    save_csv(out, out_dir / "news_items.csv")
    write_json(
        {"date": ymd, "cash_score": cash_score, "counts": counts, "headlines": headlines[:15]},
        out_dir / "news_signals.json",
    )

    return NewsSignals(cash_score=cash_score, counts=counts, headlines=headlines)

import logging
import json
import os
from typing import Any, Dict, List

from openai import OpenAI


class LLMClient:
    def __init__(self, api_key: str, base_url: str, model: str, temperature: float = 0.6):
        api_key = api_key.strip() if api_key else ""
        base_url = base_url.strip() if base_url else ""
        model = model.strip() if model else ""

        if not api_key:
            api_key = os.environ.get("MYQUANT_LLM_API_KEY", "").strip() or os.environ.get("DEEPSEEK_API_KEY", "").strip()
        if not base_url:
            base_url = os.environ.get("MYQUANT_LLM_BASE_URL", "").strip()
        if not model:
            model = os.environ.get("MYQUANT_LLM_MODEL", "").strip()

        if not api_key:
            raise RuntimeError("LLM API key missing. Set MYQUANT_LLM_API_KEY or DEEPSEEK_API_KEY.")
        if not base_url:
            raise RuntimeError("LLM base_url missing. Set MYQUANT_LLM_BASE_URL.")
        if not model:
            raise RuntimeError("LLM model missing. Set MYQUANT_LLM_MODEL.")

        self.api_key = api_key
        self.base_url = base_url
        self.model = model
        self.temperature = float(temperature)
        self.client = OpenAI(api_key=self.api_key, base_url=self.base_url, timeout=45.0, max_retries=2)

    def process_news_batch(self, news_items: List[Dict[str, str]]) -> List[Dict[str, Any]]:
        if not news_items:
            return []

        prompt = self._build_prompt(news_items)

        try:
            response = self.client.chat.completions.create(
                model=self.model,
                messages=[
                    {"role": "system", "content": "你是一位资深 A 股策略分析师。请直接输出合法的 JSON，不要做过多的解释和发散推理。"},
                    {"role": "user", "content": prompt}
                ],
                temperature=self.temperature,
                max_tokens=2200,
            )
            content = response.choices[0].message.content or ""

            content = content.strip()
            if content.startswith("```json"):
                content = content[7:]
            if content.startswith("```"):
                content = content[3:]
            if content.endswith("```"):
                content = content[:-3]
            content = content.strip()

            parsed = json.loads(content) if content else {}
            return parsed.get("results", [])
        except Exception as e:
            logging.warning(f"LLM processing failed: {e}")
            return [
                {"is_noise": True, "sentiment": 0.0, "category": "other", "strength": 1, "impacts": []}
                for _ in news_items
            ]

    def _build_prompt(self, items: List[Dict[str, str]]) -> str:
        items_str = "\n".join([f"ID:{i} | Title:{item['title']} | Content:{item.get('content', '')[:150]}" for i, item in enumerate(items)])
        return f"""
请分析以下新闻并输出严格合法的 JSON，格式为 {{"results": [...]}}，数组顺序与输入一致。
对于每条新闻：
1. 判断是否为噪音（is_noise: true/false）。噪音定义：地方性小事件、社会八卦、娱乐、品牌营销辟谣、无实质影响的盘面总结。
2. 提取情感倾向（sentiment: -1.0 到 1.0 的浮点数，-1为极度悲观/利空，1为极度乐观/利好，0为中性）。
3. 归类核心政策/信号类别（category: 必须是 "monetary"(货币政策), "fiscal_industry"(财政或产业政策), "regulatory"(监管), "international"(国际政经), "other"(其他) 之一）。
4. 影响强度（strength: 整数 1 到 3，1为弱影响，2为中等，3为重磅/突发强影响）。
5. 行业影响列表（impacts: 数组，可为空）。每个元素形如 {{"sector":"油气/军工/航运/化工/银行/房地产/新能源/旅游/消费/科技/黄金等中文行业名","direction":1或-1}}。direction=1 表示该新闻对该行业偏利好，direction=-1 表示偏利空。最多输出 3 个影响行业。

新闻列表：
{items_str}

必须只输出 JSON 数据，不要包含任何其他说明文字。
"""

