                meta_path.write_text(
                    json.dumps({"industry": str(industry_name), "symbol": symbol, "fetched_at": time.time(), "source": "em"}, ensure_ascii=False),
                    encoding="utf-8",
                )
            return df
        except Exception:
            cached = load_csv(csv_path)
            if isinstance(cached, pd.DataFrame) and not cached.empty:
                return cached
            raise

